/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataFieldEventHandler(formDataFieldStr(SalesEditLines, ETG_BillOfLading, BOLNo), FormDataFieldEventType::Modified)]
public static void BOLNo_OnModified(FormDataObject sender, FormDataFieldEventArgs e)
{
    ETG_BillOfLading    billlandingloc ;
    ETG_BillOfLading    billlading = sender.datasource().cursor();
    SalesParmTable      parmtable = sender.datasource().formRun().dataSource("SalesParmTable").cursor();
    CustPackingSlipJour custPackingSlipJour;
    CustInvoiceJour     custinvoicejour;


    if (parmtable.Ordering == DocumentStatus::PackingSlip)
    {
        select firstonly billlandingloc
            where billlandingloc.BOLNo == billlading.BOLNo
            && billlandingloc.SalesId == billlading.SalesId;
        if (billlandingloc)
        {
            billlading.BOLNo        = '' ;
            billlading.BOLDate      = dateNull() ;
            throw Error(strFmt('BOL No %1 Not Exist', billlading.BOLNo)) ;
        }

    }

